// ─── NODE 2: DATEN AUFBEREITEN + VALIDIEREN ───────────────────────────

const body = $input.first().json.body || $input.first().json;

// Pflichtfelder prüfen
const required = ['typ','angebot','adresse','flaeche','zimmer','preis','zustand'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  return [{
    json: {
      success: false,
      error: `Fehlende Pflichtfelder: ${missing.join(', ')}. Bitte alle Pflichtfelder ausfüllen.`
    }
  }];
}

// Preis formatieren
const preisNum = parseInt(String(body.preis).replace(/[^0-9]/g, ''));
const preisFormatiert = new Intl.NumberFormat('de-CH').format(preisNum);

// Merkmale
const merkmale = Array.isArray(body.merkmale) && body.merkmale.length > 0
  ? body.merkmale.join(', ')
  : 'keine besonderen Merkmale';

// Bilder-Info
const bilder = Array.isArray(body.bilder) ? body.bilder.slice(0, 10) : [];
const bildLabels = bilder.map((b, i) => `Bild ${i+1}: ${b.label || 'Zimmer ' + (i+1)}`).join(', ');

// Prompt zusammenbauen
const prompt = `Erstelle ein professionelles Immobilien-Exposé auf Schweizer Hochdeutsch.

OBJEKT-GRUNDDATEN:
- Typ: ${body.typ}
- Angebot: ${body.angebot}
- Adresse: ${body.adresse}${body.kanton ? ', ' + body.kanton : ''}
- Wohnfläche: ${body.flaeche} m²
- Zimmer: ${body.zimmer}
- Stockwerk: ${body.stockwerk || 'nicht angegeben'}
- Baujahr: ${body.baujahr || 'nicht angegeben'}
- Letzte Renovation: ${body.renovation || 'nicht angegeben'}
- ${body.angebot === 'Vermietung' ? 'Miete' : 'Kaufpreis'}: CHF ${preisFormatiert}

ZUSTAND & AUSSTATTUNG:
- Zustand: ${body.zustand}
- Heizung: ${body.heizung || 'nicht angegeben'}
- Parkierung: ${body.parkierung || 'keine'}
- Besondere Merkmale: ${merkmale}
- Weitere Infos: ${body.weiteres || 'keine'}

LAGE:
- Umgebung: ${body.umgebung || 'nicht angegeben'}
- Öffentlicher Verkehr: ${body.oev || 'nicht angegeben'}
- Einkauf / Schulen: ${body.schule || 'nicht angegeben'}

BILDER: ${bilder.length > 0 ? bildLabels : 'keine Bilder hochgeladen'}

STIL & ZIELGRUPPE:
- Ton: ${body.ton || 'Professionell'}
- Zielgruppe: ${body.zielgruppe || 'Keine Vorgabe'}

Vollständiges Exposé: 500–700 Wörter, emotionaler Einstieg, alle Details, Bilder-Beschreibungen natürlich eingeflochten.
Portal-Version: Exakt max. 1800 Zeichen, kompakt, für ImmoScout24 und Homegate optimiert.`;

return [{
  json: {
    prompt,
    bilder,
    formData: body,
    preisFormatiert
  }
}];

// ─── NODE 3: BILDER FÜR CLAUDE API AUFBEREITEN ───────────────────────

const data = $input.first().json;

// Wenn Fehler aus Node 2 → durchleiten
if (data.success === false) {
  return [{ json: data }];
}

const bilder = data.bilder || [];
const prompt = data.prompt;

// Claude message content aufbauen: erst Bilder, dann Text
const content = [];

// Bilder als Base64 image blocks
for (const bild of bilder) {
  if (!bild.data || !bild.type) continue;

  // Media type validieren
  const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];
  const mediaType = validTypes.includes(bild.type) ? bild.type : 'image/jpeg';

  content.push({
    type: 'image',
    source: {
      type: 'base64',
      media_type: mediaType,
      data: bild.data
    }
  });

  // Label als Text nach jedem Bild
  content.push({
    type: 'text',
    text: `(Bild oben: ${bild.label || 'Immobilienbild'})`
  });
}

// Haupt-Prompt als letzter Text-Block
content.push({
  type: 'text',
  text: prompt
});

return [{
  json: {
    messageContent: content,
    formData: data.formData,
    preisFormatiert: data.preisFormatiert
  }
}];

// ─── NODE 5: RESPONSE AUFBEREITEN ────────────────────────────────────

const input = $input.first().json;

// Fehler aus früheren Nodes durchleiten
if (input.success === false) {
  return [{ json: input }];
}

// Claude API Fehler abfangen
if (input.error) {
  const errMsg = input.error?.message || JSON.stringify(input.error);
  return [{
    json: {
      success: false,
      error: `Claude API Fehler: ${errMsg}`
    }
  }];
}

// Claude Antwort extrahieren
let rawText = '';
try {
  rawText = input.content?.[0]?.text || '';
} catch(e) {
  return [{
    json: {
      success: false,
      error: 'Antwort von Claude konnte nicht gelesen werden.'
    }
  }];
}

if (!rawText) {
  return [{
    json: {
      success: false,
      error: 'Claude hat keinen Text zurückgegeben. Bitte erneut versuchen.'
    }
  }];
}

// Versionen extrahieren
function extract(text, marker, nextMarker) {
  const start = text.indexOf(marker);
  if (start === -1) return '';
  const after = text.slice(start + marker.length);
  if (nextMarker) {
    const end = after.indexOf(nextMarker);
    return end === -1 ? after.trim() : after.slice(0, end).trim();
  }
  return after.trim();
}

const vollstaendig = extract(rawText, '===VOLLSTAENDIG===', '===PORTAL===');
const portal = extract(rawText, '===PORTAL===', null);

if (!vollstaendig || !portal) {
  // Fallback: ganzen Text als vollständiges Exposé
  return [{
    json: {
      success: true,
      vollstaendig: rawText.trim(),
      portal: rawText.trim().slice(0, 1800),
      warning: 'Versionen konnten nicht getrennt werden — vollständiger Text angezeigt.'
    }
  }];
}

// Portal auf 1800 Zeichen begrenzen (Sicherheit)
const portalTrimmed = portal.length > 1800 ? portal.slice(0, 1797) + '...' : portal;

return [{
  json: {
    success: true,
    vollstaendig: vollstaendig,
    portal: portalTrimmed,
    stats: {
      vollstaendigZeichen: vollstaendig.length,
      portalZeichen: portalTrimmed.length,
      model: input.model || 'claude-sonnet-4-6'
    }
  }
}];

// ─── FEHLER-HANDLER ──────────────────────────────────────────────────
// Dieser Node fängt Fehler aus dem Claude API Call ab

const error = $input.first();

return [{
  json: {
    success: false,
    error: `Verbindungsfehler zur Claude API. Bitte API Key prüfen und erneut versuchen. Details: ${error.json?.message || 'Unbekannter Fehler'}`
  }
}];
